/**
 * Token-bucket rate limiter.
 */

export class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number; // tokens per second
  private lastRefill: number;

  constructor(maxTokens: number, refillRate: number) {
    this.maxTokens = maxTokens;
    this.tokens = maxTokens;
    this.refillRate = refillRate;
    this.lastRefill = Date.now();
  }

  /**
   * Try to consume one token. Returns true if allowed, false if rate-limited.
   */
  tryConsume(): boolean {
    this.refill();

    if (this.tokens >= 1) {
      this.tokens -= 1;
      return true;
    }
    return false;
  }

  /**
   * Get the current number of available tokens.
   */
  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  /**
   * Reset the limiter to full capacity.
   */
  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefill = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = Math.max(0, now - this.lastRefill);

    const newTokens = (elapsed / 1000) * this.refillRate;

    this.tokens = Math.min(this.maxTokens, this.tokens + newTokens);

    this.lastRefill = now;
  }
}

export interface Record {
  id: number;
  name: string;
  category: string;
  value: number;
}

export type Stage = (records: Record[]) => Record[];

export type Filter = (record: Record) => boolean;

export function andFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.every((f) => f(record));
}

export function orFilter(...filters: Filter[]): Filter {
  return (record: Record) => filters.some((f) => f(record));
}

export function notFilter(filter: Filter): Filter {
  return (record: Record) => !filter(record);
}

export class Pipeline {
  private stages: Stage[] = [];
  private filters: Filter[] = [];

  addStage(stage: Stage): this {
    this.stages.push(stage);
    return this;
  }

  addFilter(filter: Filter): this {
    this.filters.push(filter);
    return this;
  }

  run(records: Record[]): Record[] {
    let result = [...records];
    if (this.filters.length > 0) {
      const combined = andFilter(...this.filters);
      result = result.filter(combined);
    }
    for (const stage of this.stages) {
      result = stage(result);
    }
    return result;
  }
}

export function doubleValues(records: Record[]): Record[] {
  return records.map((r) => ({ ...r, value: r.value * 2 }));
}

export interface CronSchedule {
  minutes: number[];
  hours: number[];
  daysOfMonth: number[];
  months: number[];
  daysOfWeek: number[];
  original: string;
}

export class CronParseError extends Error {
  constructor(message: string, public field?: string) {
    super(message);
    this.name = 'CronParseError';
  }
}

interface FieldSpec {
  name: string;
  min: number;
  max: number;
}

const FIELDS: FieldSpec[] = [
  { name: 'minute', min: 0, max: 59 },
  { name: 'hour', min: 0, max: 23 },
  { name: 'day-of-month', min: 1, max: 31 },
  { name: 'month', min: 1, max: 12 },
  { name: 'day-of-week', min: 0, max: 6 },
];

function parseNumber(token: string, spec: FieldSpec): number {
  if (!/^\d+$/.test(token)) {
    throw new CronParseError(
      `Invalid value "${token}" in ${spec.name} field`,
      spec.name
    );
  }
  const value = parseInt(token, 10);
  if (value < spec.min || value > spec.max) {
    throw new CronParseError(
      `Value ${value} out of range (${spec.min}-${spec.max}) in ${spec.name} field`,
      spec.name
    );
  }
  return value;
}

function expandRange(start: number, end: number, step: number): number[] {
  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  return values;
}

function parsePart(part: string, spec: FieldSpec): number[] {
  if (part === '') {
    throw new CronParseError(`Empty value in ${spec.name} field`, spec.name);
  }

  let rangePart = part;
  let step = 1;
  let hasStep = false;

  const slashIndex = part.indexOf('/');
  if (slashIndex !== -1) {
    hasStep = true;
    rangePart = part.slice(0, slashIndex);
    const stepToken = part.slice(slashIndex + 1);
    if (!/^\d+$/.test(stepToken)) {
      throw new CronParseError(
        `Invalid step "${stepToken}" in ${spec.name} field`,
        spec.name
      );
    }
    step = parseInt(stepToken, 10);
    if (step <= 0) {
      throw new CronParseError(
        `Step must be positive in ${spec.name} field`,
        spec.name
      );
    }
  }

  if (rangePart === '*') {
    return expandRange(spec.min, spec.max, step);
  }

  const dashIndex = rangePart.indexOf('-');
  if (dashIndex !== -1) {
    const startToken = rangePart.slice(0, dashIndex);
    const endToken = rangePart.slice(dashIndex + 1);
    const start = parseNumber(startToken, spec);
    const end = parseNumber(endToken, spec);
    if (start > end) {
      throw new CronParseError(
        `Range start ${start} greater than end ${end} in ${spec.name} field`,
        spec.name
      );
    }
    return expandRange(start, end, step);
  }

  const value = parseNumber(rangePart, spec);
  if (hasStep) {
    return expandRange(value, spec.max, step);
  }
  return [value];
}

function parseField(field: string, spec: FieldSpec): number[] {
  const values = new Set<number>();
  for (const part of field.split(',')) {
    for (const value of parsePart(part, spec)) {
      values.add(value);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronSchedule {
  if (typeof expression !== 'string' || expression.trim() === '') {
    throw new CronParseError('Expression must be a non-empty string');
  }
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new CronParseError(`Expected 5 fields, got ${fields.length}`);
  }

  const [minutes, hours, daysOfMonth, months, daysOfWeek] = fields.map(
    (field, i) => parseField(field, FIELDS[i])
  );

  return {
    minutes,
    hours,
    daysOfMonth,
    months,
    daysOfWeek,
    original: expression,
  };
}

export interface Item {
  id: string;
  name: string;
  status: "active" | "archived";
  createdAt: number;
  updatedAt: number;
}

export interface Request {
  method: "GET" | "POST" | "PUT" | "DELETE" | string;
  headers: Record<string, string>;
  params: Record<string, string>;
  body?: unknown;
}

export interface Response {
  status: number;
  body: unknown;
}

const store = new Map<string, Item>();

export function resetStore(): void {
  store.clear();
}

export function getStore(): Map<string, Item> {
  return store;
}

function ok(data: unknown, status = 200): Response {
  return { status, body: { success: true, data } };
}

function fail(status: number, error: string): Response {
  return { status, body: { success: false, error } };
}

function checkAuth(req: Request): Response | null {
  const token = req.headers["authorization"];
  if (!token) return fail(401, "Authorization required");
  if (token !== "Bearer valid-token") return fail(401, "Invalid token");
  return null;
}

function requireBody(req: Request): Response | null {
  if (!req.body) return fail(400, "Request body is required");
  return null;
}

function requireIdParam(req: Request): Response | null {
  if (!req.params["id"]) {
    return fail(400, "Validation failed: id parameter is required");
  }
  return null;
}

function findItem(id: string): Item | Response {
  return store.get(id) ?? fail(404, "Item not found");
}

function isResponse(value: unknown): value is Response {
  return (
    typeof value === "object" &&
    value !== null &&
    "status" in value &&
    "body" in value
  );
}

function validName(data: Record<string, unknown>): string | null {
  const name = data["name"];
  if (name && typeof name === "string") return name;
  return null;
}

function validStatus(
  data: Record<string, unknown>
): "active" | "archived" | null {
  const status = data["status"];
  if (status === "active" || status === "archived") return status;
  return null;
}

function handleGet(req: Request): Response {
  const id = req.params["id"];
  if (!id) return ok(Array.from(store.values()));
  const item = findItem(id);
  return isResponse(item) ? item : ok(item);
}

function handlePost(req: Request): Response {
  const bodyError = requireBody(req);
  if (bodyError) return bodyError;

  const data = req.body as Record<string, unknown>;
  const name = validName(data);
  if (!name) return fail(400, "Validation failed: name is required");

  const id = data["id"] as string | undefined;
  if (id && store.has(id)) return fail(409, "Item already exists");

  const now = Date.now();
  const item: Item = {
    id: id || `item-${now}`,
    name,
    status: "active",
    createdAt: now,
    updatedAt: now,
  };
  store.set(item.id, item);
  return ok(item, 201);
}

function handlePut(req: Request): Response {
  const error = requireBody(req) ?? requireIdParam(req);
  if (error) return error;

  const id = req.params["id"];
  const item = findItem(id);
  if (isResponse(item)) return item;

  const data = req.body as Record<string, unknown>;
  const updated: Item = { ...item, updatedAt: Date.now() };
  const name = validName(data);
  if (name) updated.name = name;
  const status = validStatus(data);
  if (status) updated.status = status;

  store.set(id, updated);
  return ok(updated);
}

function handleDelete(req: Request): Response {
  const paramError = requireIdParam(req);
  if (paramError) return paramError;

  const id = req.params["id"];
  const item = findItem(id);
  if (isResponse(item)) return item;

  store.delete(id);
  return ok({ deleted: id });
}

const routes: Record<string, (req: Request) => Response> = {
  GET: handleGet,
  POST: handlePost,
  PUT: handlePut,
  DELETE: handleDelete,
};

export function handleRequest(req: Request): Response {
  const authError = checkAuth(req);
  if (authError) return authError;

  const route = routes[req.method];
  if (!route) return fail(405, "Method not allowed");
  return route(req);
}

import { describe, it, expect } from "vitest";
import { deepMerge } from "../../starter/deep-merge.js";

describe("deepMerge", () => {
  describe("basic merging", () => {
    it("merges flat objects with distinct keys", () => {
      const result = deepMerge({ a: 1 } as Record<string, unknown>, { b: 2 });
      expect(result).toEqual({ a: 1, b: 2 });
    });

    it("source primitives overwrite target primitives", () => {
      const result = deepMerge({ a: 1, b: "x" }, { a: 2, b: "y" });
      expect(result.a).toBe(2);
      expect(result.b).toBe("y");
    });

    it("returns a new object, not the target", () => {
      const target = { a: 1 };
      const result = deepMerge(target, { a: 2 });
      expect(result).not.toBe(target);
      expect(target.a).toBe(1);
    });

    it("does not mutate the source", () => {
      const source = { a: { b: 2 } };
      deepMerge({ a: { b: 1, c: 3 } }, source);
      expect(source).toEqual({ a: { b: 2 } });
    });

    it("handles an empty source", () => {
      const target = { a: 1, b: { c: 2 } };
      const result = deepMerge(target, {});
      expect(result).toEqual({ a: 1, b: { c: 2 } });
      expect(result).not.toBe(target);
    });

    it("handles an empty target", () => {
      const result = deepMerge({} as Record<string, unknown>, { a: 1, b: [2] });
      expect(result).toEqual({ a: 1, b: [2] });
    });

    it("preserves falsy source values other than undefined", () => {
      const result = deepMerge(
        { a: 1, b: 1, c: 1 } as Record<string, unknown>,
        { a: 0, b: "", c: false }
      );
      expect(result.a).toBe(0);
      expect(result.b).toBe("");
      expect(result.c).toBe(false);
    });
  });

  describe("nested objects", () => {
    it("merges nested objects recursively instead of replacing", () => {
      const result = deepMerge(
        { a: { x: 1, y: 2 } },
        { a: { y: 3 } } as Partial<{ a: { x: number; y: number } }>
      );
      expect(result).toEqual({ a: { x: 1, y: 3 } });
    });

    it("merges deeply nested structures", () => {
      const target = { a: { b: { c: { d: 1, keep: true } } } };
      const source = { a: { b: { c: { d: 2 } } } };
      const result = deepMerge(target, source as Partial<typeof target>);
      expect(result.a.b.c.d).toBe(2);
      expect((result.a.b.c as Record<string, unknown>).keep).toBe(true);
    });

    it("does not mutate nested target objects", () => {
      const target = { a: { b: 1 } };
      const result = deepMerge(target, { a: { b: 2 } });
      expect(target.a.b).toBe(1);
      expect(result.a).not.toBe(target.a);
    });

    it("replaces a primitive target value with a source object", () => {
      const result = deepMerge(
        { a: 5 } as Record<string, unknown>,
        { a: { b: 1 } } as Record<string, unknown>
      );
      expect(result.a).toEqual({ b: 1 });
    });

    it("replaces an object target value with a source primitive", () => {
      const result = deepMerge(
        { a: { b: 1 } } as Record<string, unknown>,
        { a: 5 } as Record<string, unknown>
      );
      expect(result.a).toBe(5);
    });

    it("replaces target array with source object (no recursive merge into arrays)", () => {
      const result = deepMerge(
        { a: [1, 2] } as Record<string, unknown>,
        { a: { b: 1 } } as Record<string, unknown>
      );
      expect(result.a).toEqual({ b: 1 });
    });

    it("merges plain objects created with Object.create(null)", () => {
      const nullProtoSource = Object.create(null) as Record<string, unknown>;
      nullProtoSource.b = 2;
      const result = deepMerge(
        { a: { x: 1 } } as Record<string, unknown>,
        { a: nullProtoSource } as Record<string, unknown>
      );
      expect(result.a).toEqual({ x: 1, b: 2 });
    });

    it("replaces (does not merge) class instances", () => {
      class Point {
        constructor(public x: number) {}
      }
      const instance = new Point(9);
      const result = deepMerge(
        { a: { x: 1, y: 2 } } as Record<string, unknown>,
        { a: instance } as Record<string, unknown>
      );
      expect(result.a).toBe(instance);
      expect((result.a as Point).x).toBe(9);
      expect((result.a as Record<string, unknown>).y).toBeUndefined();
    });
  });

  describe("arrays", () => {
    it("replaces target array entirely with source array", () => {
      const result = deepMerge({ a: [1, 2, 3] }, { a: [4] });
      expect(result.a).toEqual([4]);
    });

    it("copies the source array rather than sharing the reference", () => {
      const sourceArr = [1, 2];
      const result = deepMerge({ a: [0] }, { a: sourceArr });
      expect(result.a).toEqual([1, 2]);
      expect(result.a).not.toBe(sourceArr);
      sourceArr.push(3);
      expect(result.a).toEqual([1, 2]);
    });

    it("replaces a non-array target value with a source array", () => {
      const result = deepMerge(
        { a: "hello" } as Record<string, unknown>,
        { a: [1] } as Record<string, unknown>
      );
      expect(result.a).toEqual([1]);
    });

    it("handles empty source arrays", () => {
      const result = deepMerge({ a: [1, 2] }, { a: [] as number[] });
      expect(result.a).toEqual([]);
    });

    it("handles nested arrays inside merged objects", () => {
      const result = deepMerge({ a: { list: [1], keep: 1 } }, {
        a: { list: [2, 3] },
      } as Partial<{ a: { list: number[]; keep: number } }>);
      expect(result.a.list).toEqual([2, 3]);
      expect(result.a.keep).toBe(1);
    });
  });

  describe("Date handling", () => {
    it("clones Date objects instead of sharing references", () => {
      const date = new Date("2026-07-16T00:00:00.000Z");
      const result = deepMerge({ d: new Date(0) }, { d: date });
      expect(result.d).toBeInstanceOf(Date);
      expect(result.d).not.toBe(date);
      expect(result.d.getTime()).toBe(date.getTime());
    });

    it("mutating the original Date does not affect the merged copy", () => {
      const date = new Date("2020-01-01T00:00:00.000Z");
      const original = date.getTime();
      const result = deepMerge({ d: new Date(0) }, { d: date });
      date.setFullYear(1999);
      expect(result.d.getTime()).toBe(original);
    });

    it("a Date in source replaces a plain object in target", () => {
      const date = new Date(123456);
      const result = deepMerge(
        { d: { nested: true } } as Record<string, unknown>,
        { d: date } as Record<string, unknown>
      );
      expect(result.d).toBeInstanceOf(Date);
      expect((result.d as Date).getTime()).toBe(123456);
    });

    it("clones Dates nested inside merged objects", () => {
      const date = new Date(42);
      const result = deepMerge({ a: { d: new Date(0), keep: 1 } }, {
        a: { d: date },
      } as Partial<{ a: { d: Date; keep: number } }>);
      expect(result.a.d).not.toBe(date);
      expect(result.a.d.getTime()).toBe(42);
      expect(result.a.keep).toBe(1);
    });
  });

  describe("null and undefined", () => {
    it("null in source replaces the target value", () => {
      const result = deepMerge(
        { a: 1, b: { c: 2 } } as Record<string, unknown>,
        { a: null, b: null } as Record<string, unknown>
      );
      expect(result.a).toBeNull();
      expect(result.b).toBeNull();
    });

    it("undefined in source is skipped and target value preserved", () => {
      const result = deepMerge(
        { a: 1, b: "keep" } as Record<string, unknown>,
        { a: undefined } as Record<string, unknown>
      );
      expect(result.a).toBe(1);
      expect(result.b).toBe("keep");
    });

    it("undefined for a key missing from target leaves it absent-valued", () => {
      const result = deepMerge(
        { a: 1 } as Record<string, unknown>,
        { newKey: undefined } as Record<string, unknown>
      );
      expect(result.newKey).toBeUndefined();
      expect(result.a).toBe(1);
    });

    it("null target value is replaced by a source object without merging", () => {
      const result = deepMerge(
        { a: null } as Record<string, unknown>,
        { a: { b: 1 } } as Record<string, unknown>
      );
      expect(result.a).toEqual({ b: 1 });
    });

    it("source can set null deep inside a nested merge", () => {
      const result = deepMerge({ a: { b: 1, c: 2 } }, {
        a: { b: null },
      } as unknown as Partial<{ a: { b: number; c: number } }>);
      expect((result.a as Record<string, unknown>).b).toBeNull();
      expect(result.a.c).toBe(2);
    });
  });

  describe("symbol keys", () => {
    it("copies symbol-keyed properties from source", () => {
      const sym = Symbol("key");
      const source: Record<string | symbol, unknown> = { [sym]: "value" };
      const result = deepMerge({ a: 1 } as Record<string | symbol, unknown>, source);
      expect(result[sym]).toBe("value");
      expect(result.a).toBe(1);
    });

    it("symbol-keyed source values overwrite symbol-keyed target values", () => {
      const sym = Symbol("shared");
      const result = deepMerge(
        { [sym]: "old" } as Record<string | symbol, unknown>,
        { [sym]: "new" } as Record<string | symbol, unknown>
      );
      expect(result[sym]).toBe("new");
    });

    it("preserves symbol keys already on the target", () => {
      const sym = Symbol("target-only");
      const result = deepMerge(
        { [sym]: 7, a: 1 } as Record<string | symbol, unknown>,
        { a: 2 } as Record<string | symbol, unknown>
      );
      expect(result[sym]).toBe(7);
      expect(result.a).toBe(2);
    });

    it("symbols named like forbidden keys are not filtered", () => {
      const sym = Symbol("__proto__");
      const result = deepMerge(
        {} as Record<string | symbol, unknown>,
        { [sym]: "allowed" } as Record<string | symbol, unknown>
      );
      expect(result[sym]).toBe("allowed");
    });
  });

  describe("prototype pollution protection", () => {
    it("skips an own __proto__ key from source", () => {
      const source = JSON.parse('{"__proto__": {"polluted": true}}') as Record<
        string,
        unknown
      >;
      const result = deepMerge({ a: 1 } as Record<string, unknown>, source);
      expect(({} as Record<string, unknown>).polluted).toBeUndefined();
      expect((result as Record<string, unknown>).polluted).toBeUndefined();
      expect(Object.prototype.hasOwnProperty.call(result, "__proto__")).toBe(false);
      expect(result.a).toBe(1);
    });

    it("skips the constructor key", () => {
      const source = JSON.parse(
        '{"constructor": {"prototype": {"polluted": true}}, "safe": 1}'
      ) as Record<string, unknown>;
      const result = deepMerge({} as Record<string, unknown>, source);
      expect(Object.prototype.hasOwnProperty.call(result, "constructor")).toBe(false);
      expect(result.constructor).toBe(Object);
      expect(({} as Record<string, unknown>).polluted).toBeUndefined();
      expect(result.safe).toBe(1);
    });

    it("skips the prototype key", () => {
      const source = JSON.parse('{"prototype": {"polluted": true}, "ok": 2}') as Record<
        string,
        unknown
      >;
      const result = deepMerge({} as Record<string, unknown>, source);
      expect(Object.prototype.hasOwnProperty.call(result, "prototype")).toBe(false);
      expect(result.ok).toBe(2);
    });

    it("blocks __proto__ injected through a nested merge", () => {
      const source = JSON.parse(
        '{"a": {"__proto__": {"polluted": true}, "b": 2}}'
      ) as Record<string, unknown>;
      const result = deepMerge(
        { a: { b: 1 } } as Record<string, unknown>,
        source
      );
      expect(({} as Record<string, unknown>).polluted).toBeUndefined();
      expect((result.a as Record<string, unknown>).b).toBe(2);
      expect(
        Object.prototype.hasOwnProperty.call(result.a as object, "__proto__")
      ).toBe(false);
    });

    it("does not alter Object.prototype after merging hostile input", () => {
      const hostile = JSON.parse(
        '{"__proto__": {"x": 1}, "constructor": {"y": 2}, "prototype": {"z": 3}}'
      ) as Record<string, unknown>;
      deepMerge({} as Record<string, unknown>, hostile);
      const probe = {} as Record<string, unknown>;
      expect(probe.x).toBeUndefined();
      expect(probe.y).toBeUndefined();
      expect(probe.z).toBeUndefined();
    });
  });

  describe("mixed and complex scenarios", () => {
    it("handles a mix of all value kinds in one merge", () => {
      const sym = Symbol("s");
      const date = new Date(1000);
      const target: Record<string | symbol, unknown> = {
        keepMe: "yes",
        num: 1,
        arr: [1, 2],
        nested: { a: 1, deep: { x: 1 } },
        toNull: "gone soon",
        stays: "untouched",
      };
      const source: Record<string | symbol, unknown> = {
        num: 2,
        arr: [9],
        nested: { deep: { y: 2 } },
        toNull: null,
        stays: undefined,
        d: date,
        [sym]: true,
      };
      const result = deepMerge(target, source);
      expect(result.keepMe).toBe("yes");
      expect(result.num).toBe(2);
      expect(result.arr).toEqual([9]);
      expect(result.nested).toEqual({ a: 1, deep: { x: 1, y: 2 } });
      expect(result.toNull).toBeNull();
      expect(result.stays).toBe("untouched");
      expect(result.d).toBeInstanceOf(Date);
      expect(result.d).not.toBe(date);
      expect(result[sym]).toBe(true);
    });

    it("merging an object with itself yields an equal copy", () => {
      const obj = { a: 1, b: { c: [1, 2], d: new Date(5) } };
      const result = deepMerge(obj, obj);
      expect(result).toEqual(obj);
      expect(result).not.toBe(obj);
      expect(result.b).not.toBe(obj.b);
      expect(result.b.c).not.toBe(obj.b.c);
      expect(result.b.d).not.toBe(obj.b.d);
    });

    it("shares references for non-plain, non-cloned source values", () => {
      const fn = () => 42;
      const map = new Map([["k", 1]]);
      const result = deepMerge(
        {} as Record<string, unknown>,
        { fn, map } as Record<string, unknown>
      );
      expect(result.fn).toBe(fn);
      expect(result.map).toBe(map);
    });

    it("handles NaN and other special numbers as ordinary overwrites", () => {
      const result = deepMerge(
        { a: 1, b: 2 } as Record<string, unknown>,
        { a: NaN, b: Infinity } as Record<string, unknown>
      );
      expect(Number.isNaN(result.a as number)).toBe(true);
      expect(result.b).toBe(Infinity);
    });
  });
});
